function toggleSummaryDisplay(e){let n=e.id.indexOf("-controller");if(n===-1)return;let t=document.getElementById(e.id.substring(0,n));t.style.display==="none"?(t.style.display="inherit",e.innerHTML=`<i class="fas fa-chevron-up"></i>`):t.style.display==="inherit"&&(t.style.display="none",e.innerHTML=`<i class="fas fa-chevron-down"></i>`)}